import smtplib
import os
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart

# 실제 서비스에서는 코드에 직접 쓰지 말고 환경변수로 관리하세요
SMTP_SERVER = os.environ.get("SMTP_SERVER", "smtp.gmail.com")
SMTP_PORT = int(os.environ.get("SMTP_PORT", 587))
SMTP_USER = os.environ.get("SMTP_USER")          # 보내는 계정
SMTP_PASSWORD = os.environ.get("SMTP_PASSWORD")  # 앱 비밀번호(App Password)
ALERT_RECEIVER = os.environ.get("ALERT_RECEIVER") # 알림 받을 주소


def send_email_alert(data: dict) -> None:
    """탐지된 악성 플로우 정보를 이메일로 전송합니다.

    Args:
        data (dict): flow.get_data()로 추출된 플로우 특징 + Label
    """
    subject = f"[경고] 악성 트래픽 탐지: {data.get('Src IP')} -> {data.get('Dst IP')}"

    body = (
        f"악성 트래픽이 탐지되었습니다.\n\n"
        f"Src IP   : {data.get('Src IP')}\n"
        f"Src Port : {data.get('Src Port')}\n"
        f"Dst IP   : {data.get('Dst IP')}\n"
        f"Dst Port : {data.get('Dst Port')}\n"
        f"Protocol : {data.get('Protocol')}\n"
        f"Flow Duration : {data.get('Flow Duration')} us\n"
        f"Label    : {data.get('Label')}\n"
    )

    msg = MIMEMultipart()
    msg["From"] = SMTP_USER
    msg["To"] = ALERT_RECEIVER
    msg["Subject"] = subject
    msg.attach(MIMEText(body, "plain"))

    try:
        with smtplib.SMTP(SMTP_SERVER, SMTP_PORT, timeout=10) as server:
            server.starttls()
            server.login(SMTP_USER, SMTP_PASSWORD)
            server.sendmail(SMTP_USER, ALERT_RECEIVER, msg.as_string())
        print(f"[알림] 이메일 전송 완료: {data.get('Src IP')} -> {data.get('Dst IP')}")
    except Exception as e:
        # 메일 전송 실패가 패킷 처리 흐름을 막지 않도록 예외를 여기서 흡수
        print(f"[에러] 이메일 전송 실패: {e}")
